<?php
$pageTitle = 'AI Mission Execution Console';
$pageDescription = 'Run approved AI operation missions one routed item at a time.';
$pageClass = 'membership-page admin-catalog-page ai-mission-execution-page';
require_once __DIR__ . '/../includes/admin_catalog.php';
require_once __DIR__ . '/../includes/ai_platform_execution.php';
require_once __DIR__ . '/../includes/ai_autonomy_policies.php';
require_once __DIR__ . '/../includes/ai_mission_execution.php';

if (($_SERVER['REQUEST_METHOD'] ?? 'GET') === 'POST' && ($_POST['action'] ?? '') === 'run_next_item') {
  $result = sf_ai_mission_run_next(sf_admin_int($_POST['mission_id'] ?? null, 0) ?? 0);
  sf_admin_flash(!empty($result['ok']) ? 'success' : 'error', (string)($result['message'] ?? 'Mission execution action finished.'));
  sf_admin_redirect(sf_url('admin/ai-mission-execution.php'));
}

if (($_SERVER['REQUEST_METHOD'] ?? 'GET') === 'POST' && ($_POST['action'] ?? '') === 'skip_item') {
  $result = sf_ai_mission_skip_item(sf_admin_int($_POST['item_id'] ?? null, 0) ?? 0);
  sf_admin_flash(!empty($result['ok']) ? 'success' : 'error', (string)($result['message'] ?? 'Mission skip action finished.'));
  sf_admin_redirect(sf_url('admin/ai-mission-execution.php'));
}

if (($_SERVER['REQUEST_METHOD'] ?? 'GET') === 'POST' && ($_POST['action'] ?? '') === 'recover_running') {
  $result = sf_ai_mission_recover_running(sf_admin_int($_POST['mission_id'] ?? null, 0) ?? 0);
  sf_admin_flash(!empty($result['ok']) ? 'success' : 'error', (string)($result['message'] ?? 'Mission recovery action finished.'));
  sf_admin_redirect(sf_url('admin/ai-mission-execution.php'));
}

$missions = sf_ai_mission_missions();
$counts = sf_ai_mission_counts();
require __DIR__ . '/../includes/header.php';
sf_admin_shell_start('AI Operations', 'AI Mission Execution', 'Run approved AI missions one routed item at a time.', 'ai-mission-execution');
?>
