<section class="sf-admin-panel"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow">Execution Board</span><h2><?= count($missions) ?> executable mission(s)</h2></div><div><a href="<?= sf_url('admin/ai-operations-missions.php') ?>">Mission Planner</a> · <a href="<?= sf_url('admin/ai-execution-router.php') ?>">Execution Router</a></div></div><?php if (!$missions): ?><p class="sf-exe-copy">No approved or active missions are ready for the execution console.</p><?php else: ?><div class="sf-exe-grid"><?php foreach ($missions as $mission): $items = sf_ai_mission_items((int)$mission['id']); $next = sf_ai_mission_next_item((int)$mission['id']); ?><article class="sf-exe-card"><?= sf_admin_status_badge((string)($mission['mission_status'] ?? 'approved')) ?><h3><?= sf_admin_h($mission['mission_title'] ?? 'Mission') ?></h3><p class="sf-exe-copy"><strong><?= sf_admin_h($mission['mission_area'] ?? 'ops') ?></strong> · Risk <?= sf_admin_h($mission['risk_level'] ?? 'medium') ?><br><?= (int)($mission['item_count'] ?? 0) ?> items · <?= (int)($mission['completed_count'] ?? 0) ?> complete · <?= (int)($mission['blocked_count'] ?? 0) ?> blocked</p><form method="post" class="sf-admin-form"><?= sf_csrf_field() ?><input type="hidden" name="action" value="run_next_item"><input type="hidden" name="mission_id" value="<?= (int)$mission['id'] ?>"><div class="sf-admin-form-actions"><button type="submit"<?= ($next && in_array((string)($mission['mission_status'] ?? ''), ['approved','in_progress'], true)) ? '' : ' disabled' ?>>Run Next Eligible Item</button></div></form><form method="post" class="sf-admin-form"><?= sf_csrf_field() ?><input type="hidden" name="action" value="recover_running"><input type="hidden" name="mission_id" value="<?= (int)$mission['id'] ?>"><div class="sf-admin-form-actions"><button type="submit"<?= in_array((string)($mission['mission_status'] ?? ''), ['approved','in_progress','blocked'], true) ? '' : ' disabled' ?>>Recover Running Items</button></div></form><?php foreach ($items as $item): ?><div class="sf-exe-item"><span class="sf-exe-pill">#<?= (int)$item['item_order'] ?> · <?= sf_admin_h($item['item_status'] ?? 'pending') ?> · <?= sf_admin_h($item['action_type'] ?? 'route') ?></span><p class="sf-exe-copy"><strong><?= sf_admin_h($item['title'] ?? 'Action') ?></strong><br>Action: <?= sf_admin_h(($item['approval_status'] ?? 'missing') . ' / ' . ($item['execution_status'] ?? 'missing')) ?><br><?= sf_admin_h($item['last_result_message'] ?? '') ?></p><?php if (!in_array((string)($item['item_status'] ?? ''), ['completed','skipped','running'], true)): ?><form method="post" class="sf-admin-form"><?= sf_csrf_field() ?><input type="hidden" name="action" value="skip_item"><input type="hidden" name="item_id" value="<?= (int)$item['id'] ?>"><div class="sf-admin-form-actions"><button type="submit">Skip Item</button></div></form><?php endif; ?></div><?php endforeach; ?></article><?php endforeach; ?></div><?php endif; ?></section>
